function iconPaths(name) {
  if (!name) return null;
  const k = String(name).toLowerCase().trim().replace(/_/g, "-");
  if (PATHS[k]) return PATHS[k];
  const a = ALIASES[k];
  return a && PATHS[a] ? PATHS[a] : null;
}

